// ─── LessonCard ───────────────────────────────────────────────────────────────
function LessonCard({ lesson, idx, color }) {
  const [open, setOpen] = useState(false);
  return (
    <div style={{
      borderLeft: `3px solid ${color}${open ? "80" : "28"}`,
      background: open ? "rgba(255,255,255,0.03)" : "transparent",
      borderRadius: "0 10px 10px 0", marginBottom: 5,
      transition: "all 0.22s ease", overflow: "hidden"
    }}>
      <button onClick={() => setOpen(v => !v)} style={{
        width: "100%", display: "flex", alignItems: "flex-start", gap: 12,
        padding: "12px 15px", background: "none", border: "none",
        color: open ? "#f1f5f9" : "#94a3b8", cursor: "pointer",
        textAlign: "left", fontFamily: "'DM Sans',sans-serif",
        fontSize: 13.5, transition: "color 0.2s"
      }}>
        <span style={{ color, fontWeight: 700, fontSize: 10, fontFamily: "'JetBrains Mono',monospace", minWidth: 20, marginTop: 2.5, opacity: 0.7 }}>
          {String(idx + 1).padStart(2, "0")}
        </span>
        <span style={{ flex: 1, fontWeight: 500, lineHeight: 1.5 }}>{lesson.title}</span>
        <IcChev open={open} />
      </button>
      {open && (
        <div style={{ padding: "0 15px 16px 47px", animation: "lo 0.2s ease" }}>
          <div style={{ color: "#64748b", fontSize: 13, lineHeight: 1.85, whiteSpace: "pre-line", fontFamily: "'DM Sans',sans-serif", textAlign:"left" }}>
            {lesson.content}
          </div>
          <div style={{ marginTop: 12, display: "flex", gap: 10, flexWrap: "wrap", alignItems: "center" }}>
            {lesson.link ? (
              <a href={lesson.link} target="_blank" rel="noopener noreferrer" style={{
                display: "inline-flex", alignItems: "center", gap: 4,
                color, fontSize: 11.5, textDecoration: "none", fontWeight: 600,
                opacity: 0.75, borderBottom: `1px solid ${color}35`, paddingBottom: 1,
                fontFamily: "'DM Sans',sans-serif"
              }}>
                Подробнее <IcExt />
              </a>
            ) : (
              <span style={{ fontSize: 10, color: "#1d4ed840", fontFamily: "'JetBrains Mono',monospace", background: "rgba(30,58,220,0.08)", padding: "2px 8px", borderRadius: 4 }}>
                ✦ Эксклюзив гайда
              </span>
            )}
          </div>
        </div>
      )}
    </div>
  );
}

// ─── App ─────────────────────────────────────────────────────────────────────
export default function App() {
  const [activeId, setActiveId] = useState(null);
  const [search, setSearch] = useState("");
  const top = useRef(null);

  const currentIdx = MODULES.findIndex(m => m.id === activeId);
  const current = MODULES[currentIdx];

  useEffect(() => { top.current?.scrollIntoView({ behavior: "smooth" }); }, [activeId]);

  const filtered = search.trim()
    ? MODULES.filter(m =>
        m.title.toLowerCase().includes(search.toLowerCase()) ||
        m.lessons.some(l => l.title.toLowerCase().includes(search.toLowerCase()))
      )
    : MODULES;

  const totalLessons = MODULES.reduce((a, m) => a + m.lessons.length, 0);
  const newCount = MODULES.filter(m => m.isNew).length;

  return (
    <div ref={top} style={{ minHeight: "100vh", background: "#080b16", color: "#e2e8f0", fontFamily: "'DM Sans',sans-serif", width:"100%" }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=DM+Sans:opsz,wght@9..40,400;9..40,500;9..40,600;9..40,700&family=JetBrains+Mono:wght@400;500;700&family=Fraunces:opsz,wght@9..144,700;9..144,900&display=swap');
        @keyframes su{from{opacity:0;transform:translateY(16px)}to{opacity:1;transform:translateY(0)}}
        @keyframes fi{from{opacity:0}to{opacity:1}}
        @keyframes lo{from{opacity:0;transform:translateY(-4px)}to{opacity:1;transform:translateY(0)}}
        *{box-sizing:border-box;margin:0;padding:0}
        ::-webkit-scrollbar{width:4px}::-webkit-scrollbar-track{background:#080b16}::-webkit-scrollbar-thumb{background:#1e293b;border-radius:3px}
        input,button{outline:none}
        button:hover{opacity:0.85}
      `}</style>

      {/* ── Header ── */}
      <header style={{ position:"sticky",top:0,zIndex:100,background:"rgba(8,11,22,0.93)",backdropFilter:"blur(20px)",borderBottom:"1px solid rgba(255,255,255,0.05)" }}>
        <div style={{ maxWidth:840,margin:"0 auto",padding:"0 20px",height:56,display:"flex",alignItems:"center",justifyContent:"space-between" }}>
          <button onClick={() => { setActiveId(null); setSearch(""); }} style={{ background:"none",border:"none",cursor:"pointer",display:"flex",alignItems:"center",gap:9 }}>
            <div style={{ width:28,height:28,borderRadius:7,background:"linear-gradient(135deg,#f97316,#8b5cf6)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:14 }}>🤖</div>
            <span style={{ color:"#f8fafc",fontFamily:"'Fraunces',serif",fontSize:16,fontWeight:900,letterSpacing:"-0.02em" }}>ИИ-сервис с нуля</span>
          </button>
          <span style={{ fontSize:10,color:"#1e3a5f",fontFamily:"'JetBrains Mono',monospace" }}>{MODULES.length} мод · {totalLessons} урока</span>
        </div>
      </header>

      {/* ── Home ── */}
      {!activeId && (
        <div style={{ maxWidth:840,margin:"0 auto",padding:"36px 20px 80px",animation:"fi 0.3s ease" }}>

          {/* Hero */}
          <div style={{ marginBottom:40 }}>
            <div style={{ display:"inline-flex",alignItems:"center",gap:6,padding:"4px 11px",borderRadius:20,background:"rgba(249,115,22,0.08)",border:"1px solid rgba(249,115,22,0.18)",marginBottom:16 }}>
              <span style={{ width:5,height:5,borderRadius:"50%",background:"#f97316" }}/>
              <span style={{ fontSize:10,color:"#f97316",fontFamily:"'JetBrains Mono',monospace",fontWeight:700,letterSpacing:"0.05em" }}>{newCount} модулей · {totalLessons} урока · от идеи до первых продаж</span>
            </div>
            <h1 style={{ fontFamily:"'Fraunces',serif",fontSize:"clamp(26px,5.5vw,44px)",fontWeight:900,lineHeight:1.1,letterSpacing:"-0.03em",marginBottom:12,color:"#f8fafc" }}>
              Как создать<br/>
              <span style={{ background:"linear-gradient(135deg,#f97316,#8b5cf6,#06b6d4)",WebkitBackgroundClip:"text",WebkitTextFillColor:"transparent" }}>
                собственный ИИ-сервис
              </span>
            </h1>
            <p style={{ color:"#475569",fontSize:14,maxWidth:480,lineHeight:1.7,textAlign:"left" }}>
              Полный пайплайн: от поиска идеи и валидации до вайбкодинга, деплоя и подключения платёжной системы. Именно так был создан сервис «Что ей ответить?» на mir.avotkaknado.space — без найма разработчиков.
            </p>
            <div style={{ marginTop:16,display:"flex",gap:10,flexWrap:"wrap" }}>
              <a href="https://mir.avotkaknado.space" target="_blank" rel="noopener noreferrer"
                style={{ display:"inline-flex",alignItems:"center",gap:5,padding:"7px 13px",borderRadius:8,background:"rgba(6,182,212,0.08)",border:"1px solid rgba(6,182,212,0.2)",color:"#06b6d4",fontSize:11.5,fontFamily:"'JetBrains Mono',monospace",textDecoration:"none",fontWeight:600 }}>
                🔗 Посмотреть готовый сервис <IcExt />
              </a>

            </div>
          </div>

          {/* Search */}
          <div style={{ position:"relative",marginBottom:20 }}>
            <input value={search} onChange={e => setSearch(e.target.value)}
              placeholder="Поиск по модулям и урокам..."
              style={{ width:"100%",padding:"10px 15px 10px 40px",background:"rgba(255,255,255,0.03)",border:"1px solid rgba(255,255,255,0.07)",borderRadius:9,color:"#e2e8f0",fontFamily:"'DM Sans',sans-serif",fontSize:13 }}
            />
            <span style={{ position:"absolute",left:12,top:"50%",transform:"translateY(-50%)",color:"#334155",fontSize:14 }}>🔍</span>
          </div>

          {/* Pipeline bar */}
          <div style={{ display:"flex",flexWrap:"wrap",gap:4,padding:"10px 13px",borderRadius:9,background:"rgba(255,255,255,0.015)",border:"1px solid rgba(255,255,255,0.04)",marginBottom:22 }}>
            {MODULES.map((m, i) => (
              <div key={m.id} style={{ display:"flex",alignItems:"center",gap:4 }}>
                <button onClick={() => setActiveId(m.id)}
                  style={{ padding:"3px 8px",borderRadius:5,background:`${m.color}12`,border:`1px solid ${m.color}20`,fontSize:9.5,color:m.color,fontWeight:700,fontFamily:"'JetBrains Mono',monospace",cursor:"pointer" }}>
                  {m.icon}{String(i+1).padStart(2,"0")}
                </button>
                {i < MODULES.length-1 && <span style={{ color:"#1e293b",fontSize:10 }}>›</span>}
              </div>
            ))}
          </div>

          {/* Telegram banner */}
          <a href="https://t.me/sanyaagainstreels" target="_blank" rel="noopener noreferrer"
            style={{ display:"flex",alignItems:"center",gap:14,padding:"16px 18px",borderRadius:12,background:"rgba(249,115,22,0.05)",border:"1px solid rgba(249,115,22,0.3)",marginBottom:20,textDecoration:"none",transition:"border-color 0.2s" }}>
            <img
              src="data:image/jpeg;base64,"
              alt="Александр Зайцев"
              style={{ width:52,height:52,borderRadius:"50%",objectFit:"cover",flexShrink:0,border:"2px solid rgba(249,115,22,0.4)" }}
            />
            <div style={{ flex:1,minWidth:0 }}>
              <div style={{ fontSize:13,color:"#f1f5f9",fontWeight:600,marginBottom:3,fontFamily:"'DM Sans',sans-serif",textAlign:"left" }}>Хотите создать и продавать свой ИИ-сервис?</div>
              <div style={{ fontSize:12,color:"#475569",lineHeight:1.5,fontFamily:"'DM Sans',sans-serif",textAlign:"left" }}>Я помогаю строить продукты с нуля — от идеи до первых продаж. Пишите в Telegram.</div>
            </div>
            <div style={{ padding:"8px 14px",borderRadius:7,background:"rgba(249,115,22,0.1)",border:"1px solid rgba(249,115,22,0.3)",color:"#f97316",fontSize:12,fontWeight:600,fontFamily:"'DM Sans',sans-serif",whiteSpace:"nowrap",flexShrink:0,minWidth:"max-content" }}>
              Написать →
            </div>
          </a>

          {/* Module list */}
          <div style={{ display:"flex",flexDirection:"column",gap:6 }}>
            {filtered.length === 0 && (
              <div style={{ textAlign:"center",color:"#334155",padding:"40px 0",fontSize:13 }}>
                Ничего не найдено по запросу «{search}»
              </div>
            )}
            {filtered.map((m) => {
              const realIdx = MODULES.indexOf(m);
              return (
                <button key={m.id} onClick={() => setActiveId(m.id)}
                  style={{ display:"flex",alignItems:"center",gap:14,padding:"15px 17px",background:"rgba(255,255,255,0.025)",border:"1px solid rgba(255,255,255,0.05)",borderRadius:12,cursor:"pointer",color:"#e2e8f0",textAlign:"left",transition:"all 0.18s ease",animation:`su ${0.3+realIdx*0.04}s ease both` }}>
                  <div style={{ width:40,height:40,borderRadius:11,background:`${m.color}16`,border:`1px solid ${m.color}22`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:20,flexShrink:0 }}>
                    {m.icon}
                  </div>
                  <div style={{ flex:1,minWidth:0 }}>
                    <div style={{ display:"flex",alignItems:"center",gap:7,marginBottom:2 }}>
                      <span style={{ fontFamily:"'JetBrains Mono',monospace",fontSize:9.5,color:m.color,fontWeight:700,opacity:0.65,letterSpacing:"0.06em" }}>МОД {String(realIdx+1).padStart(2,"0")}</span>
                      {m.isNew && <span style={{ fontSize:8.5,fontFamily:"'JetBrains Mono',monospace",color:"#10b981",background:"#10b98112",border:"1px solid #10b98128",padding:"1px 5px",borderRadius:3,fontWeight:700 }}>NEW</span>}
                    </div>
                    <div style={{ fontSize:14,fontWeight:600,marginBottom:2,lineHeight:1.3 }}>{m.title}</div>
                    <div style={{ fontSize:11.5,color:"#475569",lineHeight:1.3 }}>{m.desc}</div>
                  </div>
                  <div style={{ display:"flex",alignItems:"center",gap:5,flexShrink:0 }}>
                    <span style={{ fontSize:10.5,color:"#334155",fontFamily:"'JetBrains Mono',monospace" }}>{m.lessons.length}</span>
                    <span style={{ color:m.color,opacity:0.5 }}><IcArrow /></span>
                  </div>
                </button>
              );
            })}
          </div>

          {/* Telegram banner — bottom of module list */}
          <a href="https://t.me/sanyaagainstreels" target="_blank" rel="noopener noreferrer"
            style={{ display:"flex",alignItems:"center",gap:14,marginTop:20,padding:"16px 18px",borderRadius:12,background:"rgba(249,115,22,0.05)",border:"1px solid rgba(249,115,22,0.3)",textDecoration:"none",transition:"border-color 0.2s" }}>
            <img
              src="data:image/jpeg;base64,"
              alt="Александр Зайцев"
              style={{ width:52,height:52,borderRadius:"50%",objectFit:"cover",flexShrink:0,border:"2px solid rgba(249,115,22,0.4)" }}
            />
            <div style={{ flex:1,minWidth:0 }}>
              <div style={{ fontSize:13,color:"#f1f5f9",fontWeight:600,marginBottom:3,fontFamily:"'DM Sans',sans-serif",textAlign:"left" }}>Хотите создать и продавать свой ИИ-сервис?</div>
              <div style={{ fontSize:12,color:"#475569",lineHeight:1.5,fontFamily:"'DM Sans',sans-serif",textAlign:"left" }}>Я помогаю строить продукты с нуля — от идеи до первых продаж. Пишите в Telegram.</div>
            </div>
            <div style={{ padding:"8px 14px",borderRadius:7,background:"rgba(249,115,22,0.1)",border:"1px solid rgba(249,115,22,0.3)",color:"#f97316",fontSize:12,fontWeight:600,fontFamily:"'DM Sans',sans-serif",whiteSpace:"nowrap",flexShrink:0,minWidth:"max-content" }}>
              Написать →
            </div>
          </a>
        </div>
      )}

      {/* ── Module page ── */}
      {activeId && current && (
        <div style={{ maxWidth:840,margin:"0 auto",padding:"24px 20px 80px",animation:"fi 0.22s ease" }}>
          <button onClick={() => setActiveId(null)}
            style={{ display:"flex",alignItems:"center",gap:5,background:"none",border:"none",color:"#475569",cursor:"pointer",fontSize:12.5,fontFamily:"'DM Sans',sans-serif",marginBottom:24,padding:"5px 0" }}>
            <IcBack /> Все модули
          </button>

          <div style={{ marginBottom:28 }}>
            <div style={{ display:"flex",alignItems:"flex-start",gap:12,marginBottom:10 }}>
              <div style={{ width:48,height:48,borderRadius:13,flexShrink:0,background:`${current.color}16`,border:`1px solid ${current.color}22`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:24 }}>
                {current.icon}
              </div>
              <div>
                <div style={{ display:"flex",alignItems:"center",gap:7,marginBottom:5 }}>
                  <span style={{ fontFamily:"'JetBrains Mono',monospace",fontSize:9.5,color:current.color,fontWeight:700,letterSpacing:"0.06em",opacity:0.7 }}>
                    МОДУЛЬ {String(currentIdx+1).padStart(2,"0")}
                  </span>
                  {current.isNew && (
                    <span style={{ fontSize:8.5,fontFamily:"'JetBrains Mono',monospace",color:"#10b981",background:"#10b98112",border:"1px solid #10b98128",padding:"1px 5px",borderRadius:3,fontWeight:700 }}>
                      ЭКСКЛЮЗИВ ГАЙДА
                    </span>
                  )}
                </div>
                <h2 style={{ fontFamily:"'Fraunces',serif",fontSize:"clamp(18px,3.5vw,26px)",fontWeight:900,letterSpacing:"-0.02em",color:"#f8fafc",lineHeight:1.2 }}>
                  {current.title}
                </h2>
              </div>
            </div>
            <div style={{ marginLeft:60,color:"#334155",fontSize:12.5,fontFamily:"'DM Sans',sans-serif" }}>
              {current.desc} · {current.lessons.length} урока
            </div>
          </div>

          <div style={{ height:1,background:"rgba(255,255,255,0.04)",marginBottom:18 }}/>

          {current.lessons.map((lesson, idx) => (
            <LessonCard key={idx} lesson={lesson} idx={idx} color={current.color} />
          ))}

          {/* Telegram banner in module page */}
          <a href="https://t.me/sanyaagainstreels" target="_blank" rel="noopener noreferrer"
            style={{ display:"flex",alignItems:"center",gap:14,marginTop:24,padding:"16px 18px",borderRadius:12,background:"rgba(249,115,22,0.05)",border:"1px solid rgba(249,115,22,0.3)",textDecoration:"none" }}>
            <img
              src="data:image/jpeg;base64,"
              alt="Александр Зайцев"
              style={{ width:48,height:48,borderRadius:"50%",objectFit:"cover",flexShrink:0,border:"2px solid rgba(249,115,22,0.4)" }}
            />
            <div style={{ flex:1,minWidth:0 }}>
              <div style={{ fontSize:13,color:"#f1f5f9",fontWeight:600,marginBottom:3,textAlign:"left" }}>Хотите создать и продавать свой ИИ-сервис?</div>
              <div style={{ fontSize:12,color:"#475569",lineHeight:1.5,textAlign:"left" }}>Я помогаю строить продукты с нуля — от идеи до первых продаж.</div>
            </div>
            <div style={{ padding:"8px 14px",borderRadius:7,background:"rgba(249,115,22,0.1)",border:"1px solid rgba(249,115,22,0.3)",color:"#f97316",fontSize:12,fontWeight:600,whiteSpace:"nowrap",flexShrink:0,minWidth:"max-content" }}>
              Написать →
            </div>
          </a>

          <div style={{ marginTop:36,display:"flex",gap:8 }}>
            {currentIdx > 0 && (
              <button onClick={() => setActiveId(MODULES[currentIdx-1].id)}
                style={{ flex:1,padding:"12px 14px",borderRadius:10,border:"1px solid rgba(255,255,255,0.07)",background:"rgba(255,255,255,0.02)",color:"#64748b",cursor:"pointer",fontSize:12,fontFamily:"'DM Sans',sans-serif",textAlign:"left" }}>
                <div style={{ fontSize:9.5,color:"#334155",fontFamily:"'JetBrains Mono',monospace",marginBottom:2 }}>← Назад</div>
                {MODULES[currentIdx-1].icon} {MODULES[currentIdx-1].title}
              </button>
            )}
            {currentIdx < MODULES.length-1 && (
              <button onClick={() => setActiveId(MODULES[currentIdx+1].id)}
                style={{ flex:1,padding:"12px 14px",borderRadius:10,border:`1px solid ${MODULES[currentIdx+1].color}28`,background:`${MODULES[currentIdx+1].color}0e`,color:"#e2e8f0",cursor:"pointer",fontSize:12,fontFamily:"'DM Sans',sans-serif",textAlign:"right" }}>
                <div style={{ fontSize:9.5,fontFamily:"'JetBrains Mono',monospace",marginBottom:2,color:`${MODULES[currentIdx+1].color}80` }}>Вперёд →</div>
                {MODULES[currentIdx+1].icon} {MODULES[currentIdx+1].title}
              </button>
            )}
          </div>
        </div>
      )}
    </div>
  );
}
